//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    String browser;
    String module;
    List<String> files;
    Engines engines;
    Scripts scripts;
    Repository repository;
    List<String> keywords;
    String author;
    String license;
    Bugs bugs;
    String homepage;
    Dependencies dependencies;
    PeerDependencies peerDependencies;
    PeerDependenciesMeta peerDependenciesMeta;
    DevDependencies devDependencies;
    Release release;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.browser,
        required this.module,
        required this.files,
        required this.engines,
        required this.scripts,
        required this.repository,
        required this.keywords,
        required this.author,
        required this.license,
        required this.bugs,
        required this.homepage,
        required this.dependencies,
        required this.peerDependencies,
        required this.peerDependenciesMeta,
        required this.devDependencies,
        required this.release,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        browser: json["browser"],
        module: json["module"],
        files: List<String>.from(json["files"].map((x) => x)),
        engines: Engines.fromJson(json["engines"]),
        scripts: Scripts.fromJson(json["scripts"]),
        repository: Repository.fromJson(json["repository"]),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        author: json["author"],
        license: json["license"],
        bugs: Bugs.fromJson(json["bugs"]),
        homepage: json["homepage"],
        dependencies: Dependencies.fromJson(json["dependencies"]),
        peerDependencies: PeerDependencies.fromJson(json["peerDependencies"]),
        peerDependenciesMeta: PeerDependenciesMeta.fromJson(json["peerDependenciesMeta"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        release: Release.fromJson(json["release"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "browser": browser,
        "module": module,
        "files": List<dynamic>.from(files.map((x) => x)),
        "engines": engines.toJson(),
        "scripts": scripts.toJson(),
        "repository": repository.toJson(),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "author": author,
        "license": license,
        "bugs": bugs.toJson(),
        "homepage": homepage,
        "dependencies": dependencies.toJson(),
        "peerDependencies": peerDependencies.toJson(),
        "peerDependenciesMeta": peerDependenciesMeta.toJson(),
        "devDependencies": devDependencies.toJson(),
        "release": release.toJson(),
    };
}

